/**
 * Verifica si un valor es null o undefined
 * @param {*} dato
 * @returns {boolean}
 */
export const isNullOrUndefined = (dato) => {
  return dato === null || dato === undefined
}

/**
 * Verifica si un valor es null, undefined, string vacío o string "null"
 * @param {*} value
 * @returns {boolean}
 */
export const isNullOrUndefinedOrEmpty = (value) => {
  if (value === null) return true
  if (value === undefined) return true
  if (value === '') return true
  if (value === 'null') return true
  return false
}

/**
 * Verifica que el valor contenga solo letras (sin números)
 * @param {string} value
 * @returns {boolean}
 */
export const contieneNumeros = (value) => {
  const reg = new RegExp('^[a-zA-Z ]+$')
  return reg.test(value)
}
